var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"느, 늑대…….","JPN":"お、狼……","ENG":"W-wolf…","TWN":"狼……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"넌…… 저주받은 늑대인가……?","JPN":"お前は……呪われた狼か……？","ENG":"Are you… the Cursed Wolf…?","TWN":"你……就是受到詛咒的狼……？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"널…… 찾고 있었다…… 아주 오랫동안……","JPN":"お前を……探していた……長い間……","ENG":"I've been… looking for you… for a very long time…","TWN":"我……找你…… 找了好久……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"나락의 바닥에서…… 끝없는 고통에 시달리며……","JPN":"奈落の底で……果てのない苦痛を味わい……","ENG":"Writhing in eternal agony… at the bottom of the abyss…","TWN":"我在地獄……受到無止盡的痛苦……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"네게 복수할 날만을……!","JPN":"お前に復讐する日だけを……！","ENG":"Counting the days until I take revenge on you…!","TWN":"我要向你報仇……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지난번에 마주친 그 녀석도 그렇고…….","JPN":"この前会ったやつもそうだし……","ENG":"Hmm, you're just like the guy from last time…","TWN":"上次交手的那個傢伙也是……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"너희들이 왜 나를 찾는 건지, 왜 내게 그렇게 증오를 불태우는 건지 잘 모르겠어.","JPN":"あなたたちがなぜ私を探しているのか、なぜ私をそんなに憎んでいるのかはわからない。","ENG":"Look, I don't know what you want from me or why you hate me so much.","TWN":"你們到底有什麼毛病？為什麼要找我？為什麼那麼痛恨我？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어쩌면 내가 모르는 기억들 중에 그럴 만한 이유가 있을지도 모르지.","JPN":"もしかしたら私の知らない記憶の中に、その理由があるかもしれない。","ENG":"Maybe you have a pretty good reason in those memories I can't recollect.","TWN":"或許在我不知道的記憶中可能會有答案，"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 지금 난 선배를 구출하러 온 거야.","JPN":"でも今の私は先輩を助けに来たの。","ENG":"But right now, I'm here to rescue Shiyoon.","TWN":"但現在，我是來救前輩的！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까…… 여기서 네 한탄이나 들어 주고 있을 시간은 없어!","JPN":"だから……ここであなたの愚痴を聞いてやる時間なんかない！","ENG":"So I don't have time to sit around and listen to you vent!","TWN":"所以……我沒那個時間聽你廢話！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"크하아아악!!","JPN":"ぐあああああっ！！","ENG":"Graah!!","TWN":"呃啊啊啊啊！！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"피가……! 더 많은 용의 피가 필요해……!","JPN":"血が……！　もっと多くの龍の血が必要だ……！","ENG":"Blood…! Need more Dragon Blood…!","TWN":"血……！我要更多龍血……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"진정한 용이 되려면…… 더 많은 피가……!","JPN":"真の龍になるためには……多くの血が……！","ENG":"Need more blood… to become the true Dragon…!","TWN":"還要更多血……才能成為真正的龍……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 녀석, 대체 뭐야? 약해질 기미가 안 보이잖아?","JPN":"こいつ、どうなってるの？　全然弱まらないじゃん！","ENG":"What the heck is this thing? It's not getting any weaker!","TWN":"這傢伙怎麼回事？怎麼完全沒有變弱的感覺？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양! 조심하세요!","JPN":"ミナさん！　気をつけてください！","ENG":"Mina! Watch out!","TWN":"米娜，小心！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"제길, 아직도 이런 힘이……!","JPN":"ちっ、まだそんな力が……！","ENG":"Damn it, how's it still so strong?!","TWN":"可惡，竟然還這麼能打……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};